const coinData = $('Supabase → Coin Stats').first().json;
const report = $input.first().json.content?.[0]?.text || 'No report generated';

return [{ json: {
  status: 'completed',
  workflow: '20_coin_economy_health',
  coin_data_summary: {
    total_earned: coinData.total_earned || 0,
    total_spent: coinData.total_spent || 0,
    active_users: coinData.active_users || 0,
    transactions_today: coinData.transactions_today || 0
  },
  report,
  completedAt: new Date().toISOString()
} }];
